def get_promotion_tier(customer_points, has_premium_membership, participated_in_event):
    if customer_points >= 1000:
        if has_premium_membership:
            if participated_in_event:
                return "Tier 1: Elite VIP Platinum Promotion"
            else:
                return "Tier 1: Elite VIP Gold Promotion"
        else:
            if participated_in_event:
                return "Tier 1: Premium Event Access"
            else:
                return "Tier 1: Premium Points Bonus"
    elif customer_points >= 500:
        if has_premium_membership:
            if participated_in_event:
                return "Tier 2: Premium Event Discount"
            else:
                return "Tier 2: Premium Membership Perks"
        else:
            if participated_in_event:
                return "Tier 2: Standard Event Access"
            else:
                return "Tier 2: Standard Points Bonus"
    else: # customer_points < 500
        if has_premium_membership:
            if participated_in_event:
                return "Tier 3: Basic Membership Event Offer"
            else:
                return "Tier 3: Basic Membership Reward"
        else:
            if participated_in_event:
                return "Tier 3: Event Participation Gift"
            else:
                return "Tier 3: No Special Promotion"
